import{d,o as i,c as a,a as r,t as c,F as l,j as g,l as m,h as k,u as h,_ as p,n as u,w as y,v as S,b as C}from"./index-DKYUFeaD.js";import{T as j}from"./Tag-B-32NTpy.js";const v={class:"project-section"},I={class:"project-head"},B={class:"project-period"},P=["href"],R={class:"project-content"},A={class:"tag-group"},_={props:{title:{type:String,required:!0},period:{type:String,required:!0},content:{type:String,required:!0},image:{type:String,required:!0},tags:{type:Array},link:{type:String}}},b=d({..._,__name:"ProjectSection",setup(t){return h(o=>({abd9a1ae:`url(${t.image})`})),(o,s)=>(i(),a("div",v,[r("div",I,[r("div",B,c(t.period),1),r("a",{class:"project-title",href:t.link,target:"_blank",rel:"noopener noreferrer"},c(t.title),9,P),r("div",R,c(t.content),1),r("div",A,[(i(!0),a(l,null,g(t.tags,(e,n)=>(i(),m(j,{name:e,key:n},null,8,["name"]))),128))])]),r("div",{class:"project-frame",style:k({backgroundImage:`url(${t.image})`})},null,4)]))}}),f=p(b,[["__scopeId","data-v-9f904f2f"]]),N={class:"project-list"},D={class:"category"},L=["onClick"],G={data(){return{current:0,categories:["All","Web","Games","Security","AI/ML","Others"],projects:[{title:"AWS 校園智慧外送儲物櫃系統",period:"2026/02~2026/06",content:"本專案報告介紹了一套基於樹莓派與 AWS 雲端架構的「別偷我便當」智慧外送儲物櫃系統，採用 Serverless 架構以解決校園外送餐點失竊、誤領及雙方時間不一的痛點。系統核心整合了 AWS IoT Core、Lambda 與 DynamoDB 進行資料維護，並藉由 MQTT 協定與邊緣設備樹莓派 4 進行雙向控制；在安全性與功能上，系統支援一次性密碼與 AWS Rekognition 人臉辨識雙重驗證，結合 AWS SNS 提供即時到貨與異常震動報警，並導入 AWS IoT Device Shadow 實現斷網容錯與離線開鎖機制。此外，專案更透過 AWS Lex 串接 LINE Bot，允許使用者以語音或文字便捷地操作櫃位預約與查詢，成功打造出一套兼具高可用性、安全稽核與離線容錯能力的校園智慧物流自動化解決方案。",image:"/icons/projectCover/16.png",category:1,tags:["AWS","IoT","Cloud","Vue.js"],link:"https://hackmd.io/yzODAMVmQGeBhb3VD0gaAw"},{title:"Jolt: SNARKs for VM via Lookups",period:"2026/02~2026/06",content:"本報告深入探討新一代 zk-VM 架構 Jolt 的技術原理與創新優化，聚焦於其如何透過「Lookup Singularity」將 64 位元 RISC-V 指令的執行轉化為巨型表格查詢，並利用可分解性與多線性擴展大幅降低證明的承諾成本。內容詳實剖析了 Jolt 的四大核心模組，包含將複雜運算拆解為電路約束序列的虛擬指令轉換、利用時序紀錄與 Fingerprint 驗證動態記憶體一致性的 Offline Memory Checking、將巨型表拆分為免承諾子表以實現高效查表的 Lasso 協議，以及結合 Spartan 驗證執行軌跡並透過 Grand Product 檢查查表正確性的系統整合技術。整體而言，本報告全面還原了 Jolt 如何將人類程式邏輯歸約為 R1CS 密碼學矩陣方程，展現其高效率、通用性且對開發者友善的虛擬機器證明優勢。",image:"/icons/projectCover/15.png",category:3,tags:["RISC-V","SNARKs","VM","Lookups"],link:"https://hackmd.io/y47pZqoiSLKiibq5rE6zYQ"},{title:"JOP/COP Attack in RISC-V",period:"2025/09~2025/12",content:"本報告深入探討 RISC-V 架構下跳躍導向與呼叫導向程式攻擊（JOP/COP）的威脅模型與防禦機制。報告首先梳理從緩衝區溢位到代碼複用（ROP）的資安攻擊演進，指出 JOP 利用間接跳躍（indirect jump）與分派器（Dispatcher）建立惡意鏈結，繞過現有防禦，並在 RISC-V 上透過新型 ADG 劫持控制流程的技術。面對此威脅，報告系統性評估了三大防禦陣營：包含結合硬體 Shadow Stack 與 Landing Pads 的控制流程完整性（CFI）；運用 MORPHEUS 等加密技術的架構隨機化（CRA）；以及重新設計硬體、以指標權限進行邊界檢查的 CHERIoT 擴充方案。結論強調 RISC-V 仍受 JOP 威脅，防禦須在安全性、硬體成本與生態真相容性間取得平衡。",image:"/icons/projectCover/13.png",category:3,tags:["RISC-V","JOP","CHERIoT"],link:"https://hackmd.io/8Ua1v2zTR8mxEcDLS-ZTfg"},{title:"NTNU_ADMS",period:"2022/09~2022/12",content:"在 國立臺灣師範大學資工系線上申請系統 專案中，我負責 前端與後端開發 並擔任 Project Manager。這個專案將系上研究所申請流程線上化，涵蓋 線上申請、線上評分、排名及資料分析。前端使用 TypeScript 搭配 Vue.js 框架，藉由 Component 概念有效減少重複性工作；後端則選擇 Go 與 MongoDB，這是我首次接觸這兩種技術，特別是 NoSQL 資料庫的學習，讓我對後端開發有了更深入的理解。在專案中，我負責排定開發流程、監督進度並協助組員進行開發，並在有餘裕的情況下幫忙支援前端與後端的開發與內部教學。這次經驗不僅讓我提升了 Web 開發技能，也增強了我的 專案管理能力，讓專案順利完成。",image:"/icons/projectCover/1.png",category:1,tags:["Vue.js","Go","MongoDB"],link:"https://hackmd.io/@Beck049/ByGbUWj2yl"},{title:"Next.js middleware bypass",period:"2025/04~2025/05",content:"我對 CVE-2025-29927 (Next.js Middleware Bypass) 進行了深入分析，該漏洞影響 Next.js 特定版本，攻擊者可透過特製請求繞過 middleware 驗證邏輯，存取受限資源。我研究 Edge runtime 的運作機制與 middleware 執行流程，並實測利用類似 X-Forwarded-For header 功能的方式分析不同解法的利與弊，包含限制 header 來源、重構判斷邏輯與優化 matcher 規則。過程中釐清 Edge runtime 與傳統 Node.js runtime 的差異，深入理解 middleware 的請求攔截流程，並評估各種修補策略的實務風險與可行性，強化了我對 Web 應用驗證繞過防護設計的敏感度與攻防技巧。",image:"/icons/projectCover/11.png",category:3,tags:["Cybersecurity","Web"],link:"https://hackmd.io/@Beck049/H166W4Lpke"},{title:"xz-util",period:"2024/05~2024/06",content:"我對 CVE-2024-3096 (xz-utils 後門）進行了深入解析，並著重於 靜態分析動態庫 liblzma5.so。這個後門影響 xz-utils 5.6.0 和 5.6.1 版本，透過修改 liblzma，在特定條件下影響 OpenSSH 認證過程。我使用 Ghidra 針對 liblzma5.so 進行逆向分析，透過函式交叉引用與 CFG(控制流程圖)追蹤可疑邏輯，並對比不同版本的二進制代碼變化。分析過程中，我特別關注 惡意代碼的植入點、數據混淆技術，以及可能的後門觸發條件，試圖還原其行為模式。這次研究讓我更熟悉 靜態分析 ELF 動態庫 的技巧，也加深了對 惡意程式如何隱藏自身 的理解。",image:"/icons/projectCover/4.png",category:3,tags:["Cybersecurity","Ghidra"],link:"https://hackmd.io/@Beck049/BkeQuqv4R"},{title:"AI Cup - Medical SPII Detection",period:"2025/05~2025/06",content:"在「Medical SPII Recognition」競賽中，目標為提升醫療語音資料的辨識與個資抽取能力。我負責整合並微調 Whisper 與 DeepSeek 模型，分別處理語音轉文字（ASR）與命名實體辨識（NER）任務。針對硬體資源有限（NVIDIA 2070, 6GB VRAM），設計了高效訓練策略，包括混合精度訓練、LoRA 微調、4-bit 量化、梯度累積與 checkpoint 儲存等機制，成功在有限資源下完成大型語音與文字模型的訓練與推理。同時亦建構資料預處理流程，如語音增強、mel spectrogram 轉換與標註對齊，有效提升模型準確度與泛化能力。",image:"/icons/projectCover/12.png",category:4,tags:["Pytorch","Transformers","Whisper"],link:"https://hackmd.io/@Beck049/Sygh77Lb7gl"},{title:"Brain Tumor MRI",period:"2022/07~2023/06",content:"我使用 卷積神經網路（CNN） 與 instance segmentation 技術來分析 Brain Tumor MRI 影像，準確地辨識並標註腦瘤的位置。這個專案主要透過 Python 實作影像辨識與機器學習模型，以達成自動化腦瘤檢測。在過程中，我使用了 MONAI 框架 中的 UNETR（UNet Transformer） 技術進行影像標註，並在 PyTorch 中利用 CNN 模型進行訓練與學習。這樣的技術結合讓模型能夠有效提取 MRI 影像中的特徵，進行精確的腦瘤位置標註，提升了腦瘤檢測的準確性與效率。",image:"/icons/projectCover/7.png",category:4,tags:["Pytorch","CNN","Machine Learning"],link:"https://hackmd.io/@Beck049/rJyWcWs2kg"},{title:"Normal Game Jam 2025",period:"2025/05",content:"在 Game Jam 中，我使用 Godot 開發了一款 2D 繩索跑酷遊戲，並獲得了 第二名 的佳績。有了去年的經驗，今年更著重在開發流程的改進，不論是遊戲架構，合作模式都有很大的進步。",image:"/icons/projectCover/10.png",category:2,tags:["Godot"],link:"https://hackmd.io/@Beck049/SJrlI48xll"},{title:"Normal Game Jam 2024",period:"2024/05",content:"在 Game Jam 中，我使用 Godot 開發了一款 2D 地城解謎遊戲，並獲得了 第二名 的佳績。整個開發過程緊湊且充滿挑戰，從遊戲概念發想到美術、程式與關卡設計，我都投入了大量心力，並成功在短時間內完成作品。這次的比賽不僅提升了我的 Godot 開發經驗，也讓我更理解如何在有限時間內創造有趣且有深度的遊戲體驗。",image:"/icons/projectCover/3.png",category:2,tags:["Godot"],link:"https://hackmd.io/@Beck049/SkRbpirwA"},{title:"SEEDLab",period:"2022/02~2022/12",content:"我透過 SEEDLabs 實作並學習各種 資安相關議題，涵蓋 網路安全、系統安全、應用程式漏洞與攻防技術。透過實作 Buffer Overflow、SQL Injection、ARP Spoofing 等攻擊場景，我能夠深入理解漏洞的成因與攻擊者的思維。此外，我也利用 GDB、Wireshark、Burp Suite 等工具來分析與除錯，進一步強化對攻擊過程的掌握。這些實作不僅提升了我的 攻防意識與實務技能，也讓我更能從攻擊者角度思考如何加強防禦機制，對資安有了更全面的理解。",image:"/icons/projectCover/5.png",category:3,tags:["Cybersecurity"],link:"https://hackmd.io/@Beck049/B12vKZi3ke"},{title:"PokemonRL",period:"2023/09~2023/12",content:"我基於 Peter Whidden 的 PokemonRL，使用 PyBoy 模擬器建構程式與《Pokémon Red》遊戲間的 API 介面，並透過 Stable Baselines 3 進行強化學習訓練。訓練過程採用 Deep Q-Learning(DQN)，Agent透過遊玩過程學習最佳行動策略。為了提升學習效率，我優化了 狀態表示、行動空間裁剪與獎勵設計，並調整 DQN 參數來穩定訓練。在這個專案中，我結合了 強化學習、遊戲模擬與 AI 訓練，深入探索了如何讓 AI 透過試誤學習掌握複雜遊戲環境。",image:"/icons/projectCover/6.png",category:4,tags:["Pyboy","Stable Baselines 3","Reinforce Learning"],link:"https://hackmd.io/@Beck049/SJ4jt-j2yg"},{title:"XV6",period:"2023/09~2023/12",content:"我透過 xv6（MIT 的教學用 UNIX 內核） 實作 作業系統（OS） 相關概念，深入理解 系統呼叫、行程管理、記憶體管理與檔案系統 等核心機制。在實作過程中，我修改並擴展 xv6 核心，包括新增 系統呼叫（syscall）、實作 簡單排程器（scheduler），以及分析 虛擬記憶體管理（paging） 的運作方式。此外，我使用 GDB 進行內核偵錯，以深入解析核心運作細節。這次經驗不僅讓我更熟悉 OS 設計原理，也提升了我對 低階系統程式開發 的掌握能力。",image:"/icons/projectCover/2.png",category:5,tags:["Operating System"],link:"https://hackmd.io/@Beck049/HyssOKkZR"},{title:"Google Foobar",period:"2023/03~2023/04",content:"我參加了 Google Foobar 挑戰，這是一個由 Google 邀請的 程式設計解謎活動，專注於演算法與資料結構的應用。我使用 Python 解決了一系列高難度問題，包括 圖論、動態規劃、數論與最適化演算法，並透過 時間與空間複雜度分析 來提升解法效率。在這個過程中，我不僅強化了 Python 的應用技巧，也對 演算法設計與問題拆解 有了更深刻的理解。這次挑戰讓我體驗到如何在有限時間內 設計高效解法，並進一步提升了我的程式解題能力。",image:"/icons/projectCover/8.png",category:5,tags:["Python","Algorithm","Data Structure"],link:"https://hackmd.io/@Beck049/r1ji9Wjn1e"},{title:"師大暑期資工營",period:"2021/11~2022/07",content:"師大資工針對高中生而舉辦的營隊，旨在幫助高中生了解大學資工系的內容。營隊內容除了有講座、實作課程還有與資工相關的活動。我在其中擔任的角色為「總籌」，除了監督及訂定進度外，還要與各種廠商接洽，並適度的支援底下各組，以確保活動能完整進行。",image:"/icons/projectCover/9.png",category:5,link:"https://hackmd.io/@Beck049/rJcIq-jn1g"}]}}},V=d({...G,__name:"ProjectView",setup(t){return(o,s)=>(i(),a("div",N,[s[0]||(s[0]=r("h1",null,"Project List",-1)),r("div",D,[(i(!0),a(l,null,g(o.categories,(e,n)=>(i(),a("div",{class:u([{chosen:n===o.current}]),key:n,onClick:M=>o.current=n},c(e),11,L))),128))]),(i(!0),a(l,null,g(o.projects,(e,n)=>y((i(),a("div",{key:n,class:"project"},[C(f,{title:e.title,period:e.period,content:e.content,image:e.image,tags:e.tags,link:e.link},null,8,["title","period","content","image","tags","link"])])),[[S,o.current===0||e.category===o.current]])),128))]))}}),O=p(V,[["__scopeId","data-v-8f8e557f"]]);export{O as default};
